from flask import Flask, request, redirect, url_for, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Configuration
CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://your_openid_provider/authorize'
ID_TOKEN = None

@app.route('/')
def index():
    session.clear()
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&response_type=id_token&scope=openid"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    global ID_TOKEN
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
        ID_TOKEN = id_token
        return f"Authentication successful. ID Token: {id_token}"
    else:
        return "Authentication failed."

if __name__ == '__main__':
    app.run(debug=True)